import React, { useState, useEffect, useRef } from 'react';
import { Send, Paperclip, Link, ArrowLeft, Headset, Utensils, Target, AlertTriangle, Clock, CircleCheck, Power } from 'lucide-react';
import UserCard from './UserCard';

const GroupDetails = ({ group, onUserClick, onClose }) => {
  const [message, setMessage] = useState('');
  const textareaRef = useRef(null);

  // Auto-resize textarea
  useEffect(() => {
    const textarea = textareaRef.current;
    if (textarea) {
      textarea.style.height = 'auto';
      textarea.style.height = textarea.scrollHeight + 'px';
    }
  }, [message]);

  if (!group) return null;

  // Configuração dos status com cores e ícones
  const statusConfig = {
    'In meeting': {
      label: 'In Meeting',
      icon: Headset,
      color: 'text-blue-400',
      bgColor: 'bg-blue-500/10'
    },
    'Away': {
      label: 'Away',
      icon: Clock,
      color: 'text-orange-400',
      bgColor: 'bg-orange-500/10'
    },
    'Focus': {
      label: 'Focus',
      icon: Target,
      color: 'text-purple-400',
      bgColor: 'bg-purple-500/10'
    },
    'Available': {
      label: 'Available',
      icon: CircleCheck,
      color: 'text-green-400',
      bgColor: 'bg-green-500/10'
    },
    'Emergency': {
      label: 'Emergency',
      icon: AlertTriangle,
      color: 'text-red-400',
      bgColor: 'bg-red-500/10'
    },
    'Out for Lunch': {
      label: 'Out for Lunch',
      icon: Utensils,
      color: 'text-yellow-400',
      bgColor: 'bg-yellow-500/10'
    },
    'Offline': {
      label: 'Offline',
      icon: Power,
      color: 'text-gray-400',
      bgColor: 'bg-gray-500/10'
    }
  };

  const config = statusConfig[group.status] || statusConfig['Available'];
  const IconComponent = config.icon;

  const handleSendNudge = () => {
    if (message.trim()) {
      console.log(`Sending nudge to ${group.status} group: ${message}`);
      setMessage('');
    }
  };

  return (
    <div className="w-80 flex flex-col h-full border border-neutral-700 rounded-lg overflow-hidden">
      {/* Header */}
      <div className="p-6 pb-3 border-b border-neutral-700">
        <div className="flex items-center space-x-3 mb-4">
          <button
            onClick={onClose}
            className="text-neutral-400 hover:text-white transition-colors"
          >
            <ArrowLeft size={20} />
          </button>
          <h2 className="text-xl font-semibold text-white">Group Details</h2>
        </div>

        {/* Status Info */}
        <div className="flex items-center space-x-4">
          <div className={`flex items-center justify-center p-4 rounded-full ${config.bgColor}`}>
            <IconComponent size={24} className={config.color} />
          </div>
          <div>
            <h3 className="text-lg font-medium text-white">{config.label}</h3>
            <p className="text-neutral-400">{group.users.length} {group.users.length === 1 ? 'user' : 'users'}</p>
          </div>
        </div>
      </div>

      {/* Quick Nudge */}
      <div className="px-6 py-3 border-b border-neutral-700">
        <h3 className="text-lg font-medium text-white mb-3">Quick Nudge</h3>

        {/* Message Input */}
        <div className="space-y-2">
          <div className="relative">
            <textarea
              ref={textareaRef}
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              placeholder="Type your message..."
              className="w-full bg-transparent border border-neutral-600 rounded-lg px-4 py-3 text-white placeholder-neutral-400 resize-none focus:outline-none focus:border-blue-500 transition-colors min-h-[44px] overflow-hidden"
              rows="1"
              style={{ height: 'auto' }}
            />
          </div>

          {/* Action Buttons */}
          <div className="flex items-center justify-between">
            <div className="flex space-x-2">
              <button className="p-2 text-neutral-400 hover:text-white hover:bg-neutral-700 rounded-lg transition-colors">
                <Paperclip size={20} />
              </button>
              <button className="p-2 text-neutral-400 hover:text-white hover:bg-neutral-700 rounded-lg transition-colors">
                <Link size={20} />
              </button>
            </div>

            <button
              onClick={handleSendNudge}
              disabled={!message.trim()}
              className="bg-white hover:bg-neutral-200 disabled:bg-neutral-700 disabled:text-neutral-400 text-black px-4 py-2 rounded-lg flex items-center space-x-2 transition-colors"
            >
              <Send size={16} />
              <span>Send Nudge</span>
            </button>
          </div>
        </div>
      </div>

      {/* Users List */}
      <div className="flex-1 overflow-y-auto p-6 py-3">
        <h3 className="text-lg font-medium text-white mb-3">Group Members</h3>
        <div className="space-y-4">
          {group.users.map((user) => (
            <UserCard
              key={user.id}
              user={user}
              onClick={() => onUserClick(user)}
            />
          ))}
        </div>
      </div>
    </div>
  );
};

export default GroupDetails;
